const Q_CHEMISTRY_2009=[{"id": "objective>Chemistry>2009>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of sugar and sulphur can be separated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dissolution in water, evaporation and filtration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration, evaporation and dissolution in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolution in water, filtration and evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation, dissolution in water and filtration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of sugar and sulphur can be separated by dissolution in water, filtration and evaporation. Sugar is soluble in water while sulphur is not. Therefore, when the mixture is added to water, the sugar dissolves leaving the sulphur behind. The mixture can then be filtered to remove the undissolved sulphur. The filtrate, which contains the sugar solution, can then be evaporated to obtain the sugar.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2009>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a physical change?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Freezing ice-cream</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dissolving calcium in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Burning kerosene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Exposing white phosphorus to air</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Freezing ice-cream is a physical change. Physical changes are changes that affect the form of a chemical substance, but not its chemical composition. Freezing does not change the chemical composition of the ice-cream, it only changes its state from liquid to solid.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2009>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The percentage of water of crystallization in ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O is ..... <br/> [Zn = 65, S = 32, O = 16, H = 1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">33%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">44%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">55%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">87%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The molar mass of ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O is [(1 x 65) + (1 x 32) + (4 × 16) × 7(2 × 1 + 16)  <br/> = 65 + 32 + 64 + 7(18) = 161 + 126 = 287g/mol  <br/> Molar mass of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = (2 x 1) + (1 x 16) <br/> =18g/mol <br/>  Percentage of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = 126/287 × 100 = 43.9% = 44%</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2009>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">0.0075 mole of calcium trioxocarbonate (V) is added to 0.015 mole of a solution of hydrochloric acid. The volume of gas evolved at s.t.p is ..... [Molar volume of a gas at s.t.p = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">224cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">168cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">112cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction occurs according to the equation below: <br/>  CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>  <br/> 1 &nbsp &nbsp &nbsp: &nbsp &nbsp &nbsp2 <br/> 0.0075 &nbsp &nbsp &nbsp: &nbsp &nbsp &nbsp x <br/> x = 0.015 mole <br/> N.B: None of the reactants is in excess, so you can use any of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and Hcl in your calculation <br/> ∴ 1 mole of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> yields 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 0.0075 mole of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> yields x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />0.0075</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">22.4<hr size=\"1\" />x</td></tr></table></div> <br/> x = 22.4 × 0.0075 <br/> x = 0.168dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 168cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2009>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gas exert pressure on its container because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the molecules of a gas collide with the walls of the container </div>", "<div style=\"font-family:Cambria;font-size:17px;\">some of the molecules are moving faster than others </div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the collisions of the molecules with each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the mass of the molecules of the gas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gas molecules are in constant, random motion and they frequently collide with each other and with the walls of their container. When a gas molecule collides with the wall of the container, it exerts a force on the wall. The total pressure that a gas exerts on the walls of its container is the result of these many collisions.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2009>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic assumption in the kinetic theory of gases that the collision of the gaseous molecules are perfectly elastic implies that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">force of attraction and repulsion are in equilibrium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gaseous molecules can occupy any available space </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gaseous molecules will continue their motion indefinitely</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gases can be compressed</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the kinetic theory of gases, a key assumption is that the collisions between gas molecules, or between molecules and the walls of the container, are perfectly elastic. This means that the total kinetic energy of the system is conserved before and after the collision. Therefore, the molecules will continue their motion indefinitely unless acted upon by an external force.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2009>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an atom is represented as <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>X, which of the following deduction is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it contains 12 protons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it forms a covalent chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it atomic number is 23</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is an alkali metal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the atomic notation <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>X, the lower number (11) is the atomic number, which represents the number of protons in the nucleus of the atom. The atomic number determines the chemical properties of the atom, and hence its place in the periodic table. Since the atomic number is 11, the atom is sodium, which is an alkali metal.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2009>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the relative molecular mass of an element is not a whole number, it can be deduced that the element is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">naturally radioactive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abundant in nature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a transition metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an isotopic mixture</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the relative molecular mass of an element is not a whole number, it suggests that the sample of the element is a mixture of isotopes. Isotopes are atoms of the same element that have different numbers of neutrons, and hence different atomic masses. The relative atomic mass of an element is the weighted average of the atomic masses of the isotopes, taking into account their relative abundances.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2009>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cathode rays cause an object placed behind a perforated anode to cast a shadow on the screen. This observation shows that the rays</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are positively charged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are negatively charged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">travel in straight lines</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cathode rays are streams of electrons emitted from the cathode in a discharge tube. When an object is placed behind a perforated anode, the cathode rays pass through the holes and cast a shadow on the screen. This observation shows that the rays travel in straight lines.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SIMPLE HYDROGEN SPECTRUM"}, {"id": "objective>Chemistry>2009>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which quantum number divides shells into orbitals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Principal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Azimuthal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnetic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">spin</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The azimuthal quantum number, also known as the angular momentum quantum number, divides shells into orbitals. It determines the shape of the orbital and the energy of an electron in an atom. The principal quantum number defines the size and energy level of an orbital but does not divide shells into orbitals.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2009>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of bonding in {Cu(NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>}<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coordinate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrovalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It should be noted that one of the aspects in which dative bonding is effective is in the formation of complex ion like what is given above. Dative bond joins transition metal ions with ligands (that  is electron pair donor) to form complexes.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2009>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mixture of gases used in photographer's flash tube is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">argon and krypton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">krypton and xenon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helium and argon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">argon and xenon</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Krypton is used in very bright electric lamps, such as photographic flash lamps, and stroboscopes.  <br/>  Xenon is used in bright flash lamps and in lighthouses.  <br/>  Krypton and xenon are also used in lasers. <br/> They are used for high-speed pictures</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2009>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium trioxocarbonate (IV) decahydrate loses its water of crystallization to the atmosphere, the process is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deliquescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efflorescene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hygroscopic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">effervescence</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium trioxocarbonate (IV) decahydrate loses its water of crystallization to the atmosphere, the process is called efflorescence. Efflorescence is the process in which a substance loses water of crystallization to the atmosphere on exposure to air.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2009>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water can be obtained as the only product during the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">combustion of hydrocarbons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutralization of an acid by a base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combustion of hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrolysis of brine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water can be obtained as the only product during the combustion of hydrogen. When hydrogen gas burns in the presence of oxygen, the only product formed is water. The reaction is 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O(g).</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2009>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 10.5g of lead (II) trioxonitrate (V) is dissolved in 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of distilled water at 18<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C, the solubility of the solute in mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> is .....[Pb = 207, N = 14, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">525.00</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Mass of lead (II) trioxonitrate (V) = 10.5g <br/> molar mass of Pb(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 331gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">no.</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">mole</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />molar mass</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10.5<hr size=\"1\" />331</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.032mole</td></tr></table></div> <br/> Volume = 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.02dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">(in</td><td style=\"text-align:center;\">moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.032<hr size=\"1\" />0.02</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">32<hr size=\"1\" />20</td></tr></table></div> <br/>  = 1.6 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2009>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a given solute, the concentration of its saturated solution in different solvents are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the same at the same temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different at the same temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same at different temperatures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility of a solute in a solvent depends on the nature of both the solute and the solvent. Therefore, the concentration of a saturated solution of a given solute will be different in different solvents, even at the same temperature.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2009>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major source of oxides of nitrogen is from the burning of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fuel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorofluorocarbons</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major source of oxides of nitrogen is from the burning of fuels. This is because fuels, especially fossil fuels, contain nitrogen compounds that form oxides of nitrogen when burnt.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2009>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The acid used in electrolysis of water is dilute </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The acid used in the electrolysis of water is dilute sulfuric acid (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>). This is because sulfuric acid is a strong acid that can ionize completely in water to produce a large number of ions for the conduction of electricity.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2009>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of 1.5M solution of KOH would contain 0.045 moles?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">67.50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.75cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> molar concentration = 1.5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> no. of moles = 0.045mole <br/> volume = unknown <br/> no. of moles = molar concentration × volume <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">no of moles<hr size=\"1\" />molar concentration</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.045<hr size=\"1\" />1.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">45<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />100</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> Volume = 0.03dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 30.00 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2009>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The salt formed from the reaction between citric acid and sodium hydroxide in solution will be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acidic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">basic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">complex </div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It will be a basic salt. Note that when a weak acid reacts with a strong base, the salt formed will be basic. But in a case where a strong acid reacts with a weak base, the salt formed will be acidic.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2009>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The colour range observed when testing for reduction agents using acidified potassium heptaoxodichromate (VI) solution is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yellow to purple </div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange to green </div>", "<div style=\"font-family:Cambria;font-size:17px;\">green to orange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">purple to yellow</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When testing for reducing agents using acidified potassium heptaoxodichromate (VI) solution, the colour change observed is from orange to green. This is because potassium heptaoxodichromate (VI) is an orange solution that turns green when it is reduced.</div>", "topic": "OXIDATION AND REDUCTION : TEST FOR OXIDIZING AND REDUCING AGENTS"}, {"id": "objective>Chemistry>2009>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation state of Cr in K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> <br/> (2 x +1) + (2 x Cr) + (7 x -2) = 0 <br/> +2 + 2Cr - 14 = 0 <br/> 2Cr = +14 -2 <br/> 2Cr = +12 <br/> Divide both side by 2 <br/> Cr =  +6.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2009>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following metals is purified commercially by electrolysis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper (Cu) is one of the metals that is purified commercially by electrolysis. During the process, impure copper is used as the anode and pure copper as the cathode. The impure copper loses electrons and dissolves, while pure copper is deposited at the cathode.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2009>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What current will deposit 3.25g of Zinc in 2hrs? [Zn = 65, F = 96500 mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.25A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.34A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.67A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> 2F → 65g <br/> xF → 3.25g <br/> 65x = 6.5 <br/> x = 0.01F <br/> N.B: 1F = 96,500C <br/> 0.01F = 965C <br/> Recall: Q = It ----------* <br/> 965 = I × 2 × 3600 <br/> I = 965/7200 = 0.134A</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2009>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  <br/>  ∆G for the reaction above at 1300K is -43KJ. At this temperature, the reaction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">not feasible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at equilibrium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feasible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exothermic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The given reaction is feasible because the Gibbs free energy change (∆G) is negative. In thermodynamics, a negative ∆G indicates that the reaction can occur spontaneously, which means it is feasible.</div>", "topic": "ENERGY CHANGES : SPONTANEITY OF REACTIONS"}, {"id": "objective>Chemistry>2009>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two equal bulbs, one containing ammonia and the other nitrogen, are open mouth-to-mouth to each other at room temperature. The entropy in the mixture of gases is likely to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remain unchanged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">change</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entropy is a measure of disorder or randomness. When two gases mix, the disorder of the system increases because the molecules of the two gases are more randomly distributed in the mixture than in the separate gases. Therefore, the entropy in the mixture of gases is likely to increase.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2009>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, which of the curves represents the evolution of oxygen with time in the equation 2KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span>  → 2KCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 3O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Curve R best represents the evolution on of oxygen. Note that as a chemical reaction proceeds, the concentration of the reactant decreases while that of the product increases.</div>", "topic": "RATE OF CHEMICAL REACTION : CONCENTRATION OR TIME CURVES"}, {"id": "objective>Chemistry>2009>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A catalyst increases the rate of a chemical reaction by providing a path that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raises the activation energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases the temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lowers the activation energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases the concentration </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A catalyst works by providing an alternative reaction pathway with a lower activation energy. The activation energy is the minimum energy required for a reaction to occur. By lowering the activation energy, a catalyst increases the rate of a chemical reaction.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2009>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CuO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  <br/> What is the effect of increasing the pressure on the equilibrium reaction above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium is shifted to the left</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium is shifted to the right </div>", "<div style=\"font-family:Cambria;font-size:17px;\">There is no effect </div>", "<div style=\"font-family:Cambria;font-size:17px;\">More H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> is produced </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> CuO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> Since all the chemical species in the equation are not gaseous, then pressure change can not have effect.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2009>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium of an endothermic reaction which proceeds with an increase in volume can be shifted in the reverse direction by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the temperature and decreasing the pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the pressure and increasing the temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the temperature and increasing the pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the pressure and decreasing the temperature </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Le Chatelier's principle, an endothermic reaction (one that absorbs heat) can be shifted in the reverse direction by decreasing the temperature and increasing the pressure. Decreasing the temperature makes the system respond by favoring the exothermic reaction (the reverse reaction) to produce more heat. Increasing the pressure shifts the equilibrium to the side with fewer gas molecules, which is the reverse direction if the reaction proceeds with an increase in volume.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2009>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation of ammonia in excess air produces</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It produces NO in the presence of heated platinum catalyst.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2009>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen Sulphide gas can act as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dehydrating agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bleaching agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reducing agent </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulfide acts as a reducing agent, especially in the presence of base, which forms SH−. At high temperatures or in the presence of catalysts, sulfur dioxide reacts with hydrogen sulfide to form elemental sulfur and water.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2009>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gasification of coke is used for the manufacture of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">producer gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">synthetic gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial gas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gasification of coke is used for the manufacture of producer gas. Producer gas is fuel gas that is made by passing air over red-hot coke. Therefore, the correct answer is producer gas.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2009>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that is most useful in protecting humans against solar radiations is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ozone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that is most useful in protecting humans against solar radiations is Ozone. The ozone layer absorbs most of the Sun's harmful ultraviolet radiation. Therefore, the correct answer is ozone.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2009>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the allotrope of carbon is a constituent of a lead of pencil? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">graphite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diamond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lampblack</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soot</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The allotrope of carbon that is a constituent of a lead of pencil is Graphite. Graphite is a form of carbon in which the carbon atoms are arranged in layers. Therefore, the correct answer is graphite.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2009>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following metals will show the highest metallic character? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Barium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Metallic character increases down a group in the periodic table. This is because as you move down a group, the atomic size increases. This increase in size means that the outermost electrons are further from the nucleus and are therefore held less tightly. This makes it easier for the atom to lose these electrons and form positive ions, which is a characteristic of metals. Among the given options, Barium is the furthest down the periodic table, so it will show the highest metallic character.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2009>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Copper metal dissolves in concentrated trioxonitrate (V) acid with the resultant evolution of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When copper metal reacts with concentrated nitric acid (trioxonitrate (V) acid), it forms copper nitrate, water, and nitrogen dioxide (NO2). The reaction is: Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 4HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span> → Cu(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>. Therefore, the resultant evolution is NO2.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2009>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of iron that is best suited for welding, making nails, chains and iron rods is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pig iron </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wrought iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cast iron </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron pyrites</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wrought iron is the best type of iron for welding, making nails, chains, and iron rods. This is because it is very pure and contains only a small amount of carbon, which makes it soft, malleable, and ductile. These properties make it ideal for shaping and welding.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2009>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolytic extraction of aluminium, the function of the molten cryolite is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">precipitate aluminium hydroxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower the melting point of aluminium oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">act as a raw material </div>", "<div style=\"font-family:Cambria;font-size:17px;\">act as a solvent </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolytic extraction of aluminium, molten cryolite is used to lower the melting point of aluminium oxide. This makes the process more energy-efficient, as less heat is required to melt the aluminium oxide and carry out the electrolysis.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2009>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the products of the thermal decomposition of sodium trioxonitrate (V) is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sodium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium dioxonitrate (III) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium oxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium trioxonitrate (V) is thermally decomposed, it forms sodium nitrite (sodium dioxonitrate (III)) and oxygen. The reaction is: 2NaNO3(s) -> 2NaNO2(s) + O2(g). Therefore, one of the products of the thermal decomposition of sodium trioxonitrate (V) is sodium dioxonitrate (III).</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2009>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cracking process in petroleum refining can be represented by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heptane to heptane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heptane to 3-methylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heptane to propene and butane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heptane to 2,3,3-trimethybuthane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cracking is a process in petroleum refining where long-chain hydrocarbons are broken down into smaller, more useful hydrocarbons. Heptane (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span>) can be cracked into propene (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>) and butane (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>).</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2009>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following molecules has two positional isomers?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Br</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHBrCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CHBrCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Br</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Positional isomers are compounds with the same molecular formula but different arrangements of the functional group. CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHBrCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> has two other positional isomers: 1-bromo propane and 2-bromo propane.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2009>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following class of compounds can exist as dipolar ions in solution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fatty acids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dialkanoic acids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amino acids</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amino acids can exist as dipolar ions (also known as zwitterions) in solution. This is because they contain both an acidic carboxyl group (-COOH) and a basic amino group (-NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), which can ionize to give a positive and a negative charge within the same molecule.</div>", "topic": "ORGANIC COMPOUNDS : AMINES"}, {"id": "objective>Chemistry>2009>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lucas reagent is used to test for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkanes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoic acids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amines </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lucas reagent is a solution of anhydrous zinc chloride in concentrated hydrochloric acid. It is used in the laboratory to test for the presence of alkanols (or alcohols). The reaction with the alcohol results in the formation of a chloroalkane, which is insoluble in the mixture and forms a separate layer or a cloudy appearance.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2009>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound commonly used for sterilization and preservation of specimens and food is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">benzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ether </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ammonia</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol is commonly used for sterilization and preservation of specimens and food because of its ability to denature proteins and dissolve lipids, which makes it effective at killing many types of microbial life forms.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2009>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organic compound reacted with bromine water to give a colourless solution. The compound is probably an</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkene or alkyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanone</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of an organic compound with bromine water is a test for unsaturation. If the solution decolorizes, it means the compound is an unsaturated compound, which could be an alkene or alkyne. Alkenes and alkynes have carbon-carbon double or triple bonds respectively, which can react with bromine water to form a colorless solution.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2009>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following hydrocarbons is mainly used as fuel?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">methylene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethylene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Methane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethyne</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Methane is the main component of natural gas, which is widely used as a fuel. It is a simple hydrocarbon with the formula CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>. When it is burned in the presence of oxygen, it releases a large amount of energy, making it an efficient fuel.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2009>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The molecular formula for a common organic laboratory anaesthetic is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CHCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CHl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CHF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The molecular formula for a common organic laboratory anaesthetic is CHCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, which is known as Chloroform. Chloroform was once widely used as an anesthetic during surgeries, but it has largely been replaced by safer and more effective methods.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2009>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The simplest branched-chain hydrocarbon is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">butane</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The simplest branched-chain hydrocarbon is butane. Butane has four carbon atoms. It can have a branched structure when one of the hydrogen atoms in the second carbon atom is replaced by a methyl group (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>), resulting in a compound called 2-methylpropane, which is a form of butane.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2009>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Organic molecules that have the suffix-ene are unsaturated hydrocarbons that have </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a single bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a double bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a triple bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an ionic bond</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organic molecules that have the suffix -ene are unsaturated hydrocarbons that have a double bond. The presence of a double bond between carbon atoms is what characterizes alkenes, which are named with the suffix -ene. For example, ethene (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) is an alkene with a double bond between the two carbon atoms.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}];
